def fib(n: int) -> int:
    """
    Returns the nth Fibonacci number using memoization.
    fib(0) = 0, fib(1) = 1.
    """
    if n < 0:
        raise ValueError("Input must be a non-negative integer")

    # Dictionary to store computed Fibonacci numbers (memoization table)
    memo = {0: 0, 1: 1}

    def fib_recursive(k):
        if k in memo:
            return memo[k]

        # Recursive step: F(k) = F(k-1) + F(k-2)
        result = fib_recursive(k - 1) + fib_recursive(k - 2)

def get_nested_value(data, keys):
    """
    Safely retrieves a nested value from a dictionary or list structure.

    Returns None if data is not indexable, if a key is missing, or if
    any intermediate step fails.
    """
    result = data
    for key in keys:
        try:
            result = result[key]
        except (TypeError, KeyError):
            return None  # Return None

class Node:
    """
    A node in the Doubly Linked List for the LRU cache.
    """
    def __init__(self, key=None, value=None):
        self.key = key
        self.value = value
        self.prev = None
        self.next = None

class LRUCache:
    """
    Implements an LRU Cache with O(1) time complexity for both get and put operations.
    """
    def __init__(self, capacity: int):
        if capacity <= 0:
            raise ValueError("Capacity must be a positive integer.")
